function bridgeStoryToProse(v){
  if(typeof v==='string'){
    const i=v.indexOf('---COACHING NOTE---')
    return i>=0?v.slice(0,i).trim():v.trim()
  }
  // Legacy decoder: pre-2026-05-31 records carry outputs.p6 as object; normalizeProfileState preserves it without migration. Do not delete this branch.
  if(!v||typeof v!=='object'||!v.bridge_story)return ''
  // Prefer the user's freeform version when they have written one. This is
  // the version they will actually speak; downstream consumers (LinkedIn
  // Remix p8, Interview Prep p11, Opportunity Playbook op) read it via
  // bridgeStoryToProse and get the finished piece, not the workshop output.
  if(typeof v.user_freeform==='string'&&v.user_freeform.trim()&&!v.user_freeform.includes('[object Object]'))return v.user_freeform.trim()
  const bs=v.bridge_story,up=v.user_picks||{}
  const pick=(key,slot)=>{
    if(!slot)return ''
    const u=up[key]
    if(u&&typeof u.edited_text==='string'&&u.edited_text.trim())return u.edited_text.trim()
    if(u&&u.picked_id){const o=(slot.options||[]).find(x=>x&&x.id===u.picked_id);if(o&&o.text)return o.text}
    const f=(slot.options||[])[0];return f&&f.text?f.text:''
  }
  return [pick('slot1',bs.slot1_human_anchor),pick('slot2',bs.slot2_career_manifestation),pick('slot3',bs.slot3_forward_move)].filter(Boolean).join(' ')
}
// Guard for prose-output interpolations. Returns the string unchanged when
// it is a non-empty real string, empty string otherwise. Catches non-string
// values and the persisted "[object Object]" coercion bug so prompts never
// embed corrupted foundation content. Pairs with the normalizeProfileState
// heal that clears corruption on load.
// _opAnyBuiltFor / _opAllBuiltFor (PR — op PDF export): top-level predicates
// for the Save as PDF affordances. Hoisted from the inline opCardDone helper
// inside the op case body so the footer gate (showPlaybookFooter) and the
// inline "All five sections built" cue can share the same five-card definition.
// Keys mirror the PR #114 / PR #115 op surface: p5, p6, p_res, p11, companyRead.
function _opAnyBuiltFor(record){
  if(!record||record.schemaVersion!==2||!record.sections)return false
  const sec=record.sections
  return ['p5','p6','p_res','p11','companyRead'].some(k=>{
    const v=sec[k]
    if(k==='p6')return !!(v&&bridgeStoryToProse(v).trim())
    return !!(v&&v.content&&v.content.trim())
  })
}
function _opAllBuiltFor(record){
  if(!record||record.schemaVersion!==2||!record.sections)return false
  const sec=record.sections
  return ['p5','p6','p_res','p11','companyRead'].every(k=>{
    const v=sec[k]
    if(k==='p6')return !!(v&&bridgeStoryToProse(v).trim())
    return !!(v&&v.content&&v.content.trim())
  })
}
// interviewPrepToProse (PR — op PDF export): markdown-flattens the p11
// structured JSON for the hidden PDF assembled-doc block. Lifted from the p11
// branch of the (now removed) opSectionsMarkdown function. The op surface's
// live renderInterviewPrep component uses cream-on-dark inline styles unsuitable
// for print; this helper produces print-clean text consumable by <MD/>.
function interviewPrepToProse(content){
  const ip=parseInterviewPrepJSON(content)
  if(!ip)return ''
  return ip.questions.map((q,i)=>{
    let x=(i+1)+'. '+q.question
    if(q.type==='behavioral'&&q.star_breakdown){
      ['S','T','A','R'].forEach(kk=>{
        const y=q.star_breakdown[kk]
        if(y&&y.raw_material)x+='\n   '+kk+': '+y.raw_material
      })
    }else if(q.framing_recommendation){
      x+='\n   '+q.framing_recommendation
    }
    return x
  }).join('\n\n')
}
