const OP_LANE_TO_LANE={FG:'familiar',II:'insider',WTM:'wtm'}
const opLaneLabel=(v)=>LANE_LABELS[OP_LANE_TO_LANE[v]]||''
function opLaneValue(rec){const l=rec&&rec.opLane;if(l&&typeof l==='object'&&(l.value==='FG'||l.value==='II'||l.value==='WTM'))return l.value;return ''}
const OP_LANE_INFER_PROMPT=(jd,profileSummary,quickTakeaway)=>`Determine which of the user's three career lanes best fits a specific opportunity FOR THIS USER. Output JSON only, no preamble.\n\nThe lanes:\n- FAMILIAR GROUND (FG): continues the user's trajectory. Same function, similar industry and altitude. The user can step in and add value from day one.\n- INDUSTRY INSIDER (II): translates the user's expertise across an industry or sector shift. Function carries; context changes. The user brings credibility and an outside perspective.\n- WORK THAT MATTERS (WTM): a deliberate pivot toward something the user cares about more, away from prior trajectory. Hiring requires explaining motivation, learning velocity, and transferable capability beyond resume fit.\n\nTHIS OPPORTUNITY (job description):\n${jd}\n\nTHE USER'S FOUNDATION:\n${profileSummary}\n\nWHAT WE HAVE ALREADY SAID ABOUT ROLE-FIT:\n${quickTakeaway}\n\nReturn exactly this JSON shape:\n{"value":"FG or II or WTM","confidence":"high or medium or low","reasoning":"2 to 4 sentences. Reference at least one specific JD fact and at least one specific user-profile fact. Plain language."}\n\nRules: choose exactly one lane, no between-lanes answers. Confidence is high only when the signal is unambiguous; medium is the common case. Generic reasoning is wrong.`
async function inferLaneForOpportunity(jd,profileSummary,quickTakeaway){
  try{
    const raw=await callClaude(OP_LANE_INFER_PROMPT((jd||'').slice(0,8000),(profileSummary||'').slice(0,4000),(quickTakeaway||'').slice(0,2000)),{maxTokens:500,temperature:0.2})
    const a=raw.indexOf('{'),b=raw.lastIndexOf('}')
    if(a<0||b<0||b<=a)return null
    let obj;try{obj=JSON.parse(raw.slice(a,b+1))}catch(e){return null}
    if(!obj||(obj.value!=='FG'&&obj.value!=='II'&&obj.value!=='WTM'))return null
    const conf=(obj.confidence==='high'||obj.confidence==='low')?obj.confidence:'medium'
    return {value:obj.value,confidence:conf,reasoning:typeof obj.reasoning==='string'?obj.reasoning.trim().slice(0,800):''}
  }catch(e){return null}
}
const INFER_JD_METADATA_PROMPT=(jd)=>`Extract the hiring company, the role title, and the work location from this job description. Output JSON only, no preamble.

Job description:
${jd}

Return exactly this JSON shape:
{"company":"<company name, or empty string>","role":"<role title as posted, or empty string>","location":"<city or region, or Remote, or empty string>"}

Rules: use the company name exactly as written. For role, use the posted title, trimmed. For location, give the primary location or "Remote". If a field is not stated in the JD, use an empty string. Do not guess or invent any field.`
// inferJdMetadata: pulls company / role / location off a JD via a small focused
// LLM call. Mirror of inferLaneForOpportunity / inferIndustry. Always resolves to
// an object with empty-string defaults so callers never null-check.
async function inferJdMetadata(jd){
  const empty={company:'',role:'',location:''}
  try{
    const text=((jd)||'').slice(0,6000)
    if(!text.trim())return empty
    const raw=await callClaude(INFER_JD_METADATA_PROMPT(text),{maxTokens:300,temperature:0.2})
    const a=raw.indexOf('{'),b=raw.lastIndexOf('}')
    if(a<0||b<0||b<=a)return empty
    let obj;try{obj=JSON.parse(raw.slice(a,b+1))}catch(e){return empty}
    if(!obj||typeof obj!=='object')return empty
    const s=v=>(typeof v==='string'?v.trim().slice(0,120):'')
    return {company:s(obj.company),role:s(obj.role),location:s(obj.location)}
  }catch(e){return empty}
}
// === Company Read module helpers (PR-1) ===
// Industry rubric mapping. Deterministic; the classifier returns one of these
// keys and the rubric text below is injected verbatim into the Company Read
// prompt. No LLM judgment at generation time on which sources apply per industry.
const INDUSTRY_RUBRICS = {
  healthcare: 'CMS Star Ratings (Medicare 5-star healthcare quality ratings); Leapfrog Hospital Safety Grade (A-F letter grades for patient safety); Magnet nursing designation (ANCC recognition of nursing excellence); Joint Commission survey findings (accreditation reports). Search for these specifically; include the actual ratings or scores with source URLs.',
  tech: 'Engineering blog cadence (frequency and depth of technical posts); GitHub activity (repo count, commit cadence, star counts on public projects); open source velocity (contributions to mainstream OSS); recent product launches (release blogs, Hacker News appearances). Search for these specifically; include URLs to specific blog posts, repos, or launch announcements.',
  financial_services: 'FINRA BrokerCheck (where applicable to the role or firm); OCC enforcement actions (consent orders, fines on regulated banks); recent earnings posture (revenue trajectory, guidance changes). Search for these specifically; include URLs to filings or press coverage.',
  pharma: 'FDA inspection observations (483 forms, warning letters); clinical trial registry (active and recent trials on ClinicalTrials.gov); recent earnings posture (pipeline health, drug-launch outcomes). Search for these specifically; include URLs.',
  government_contractor: 'SAM.gov registration status (active, exclusions); USAspending.gov totals (recent contract dollars by agency); recent contract wins (defense.gov press releases, GovExec coverage). Search for these specifically; include URLs.',
  nonprofit: '990 financials via ProPublica Nonprofit Explorer (revenue, executive compensation, program ratio); charitable filings (state attorney-general databases where applicable); mission-alignment signal (recent annual reports, public-facing impact metrics). Search for these specifically; include URLs.',
  higher_education: 'Accreditation status (regional accreditor body, recent actions); enrollment trends (IPEDS data via NCES); US News rankings (recent placement and movement). Search for these specifically; include URLs.',
  retail_consumer: 'Same-store sales trends (recent quarterly earnings); recent earnings posture (guidance and direction); app store rating signal (Apple or Google ratings for consumer apps) and BBB rating (Better Business Bureau accreditation and complaint volume). Search for these specifically; include URLs.',
  manufacturing: 'OSHA citations (recent serious or willful citations); recent earnings posture; plant closures or expansions (Reuters or Bloomberg coverage of capital allocation). Search for these specifically; include URLs.',
  default: 'News from the last 90 days (acquisitions, leadership changes, funding rounds, layoffs); LinkedIn headcount trajectory (growth or contraction over recent quarters); Best Companies cross-reference (Fortune Best Workplaces, Great Place to Work certifications, Glassdoor Best Places to Work — note these where present, do not invent them). Include URLs.',
}
// inferIndustry: classifies the JD into one of the rubric keys via a small
// focused LLM call. Mirror of inferLaneForOpportunity. Returns one of the
// INDUSTRY_RUBRICS keys, defaulting to 'default' on any failure.
const INFER_INDUSTRY_PROMPT=(jd)=>`Determine the primary industry of the company hiring for this role. Output JSON only, no preamble.

Read the job description:
${jd}

Return one of these industry keys based on the company's primary industry:
- "healthcare" — hospital systems, payors, providers, digital health, health-tech
- "tech" — software, internet, SaaS, dev tools, infrastructure, consumer tech
- "financial_services" — banks, asset managers, insurance, broker-dealers, lending
- "pharma" — pharmaceutical, biotech, medical devices
- "government_contractor" — defense, federal services, government IT contractors
- "nonprofit" — 501(c)(3) organizations, foundations, NGOs
- "higher_education" — universities, colleges, education-policy organizations
- "retail_consumer" — retail, consumer brands, e-commerce, hospitality, food service
- "manufacturing" — industrial, materials, energy, automotive, aerospace
- "default" — none of the above, or the JD does not name the industry clearly

Return exactly this JSON shape:
{"industry":"<one of the keys above>","confidence":"high or medium or low"}

Rules: choose exactly one key. Use "default" rather than guessing when the JD is ambiguous.`
async function inferIndustry(ctx){
  try{
    const jd=((ctx&&ctx.jd)||'').slice(0,6000)
    if(!jd.trim())return 'default'
    const raw=await callClaude(INFER_INDUSTRY_PROMPT(jd),{maxTokens:500,temperature:0.2})
    const a=raw.indexOf('{'),b=raw.lastIndexOf('}')
    if(a<0||b<0||b<=a)return 'default'
    let obj;try{obj=JSON.parse(raw.slice(a,b+1))}catch(e){return 'default'}
    if(!obj||typeof obj.industry!=='string')return 'default'
    return Object.prototype.hasOwnProperty.call(INDUSTRY_RUBRICS,obj.industry)?obj.industry:'default'
  }catch(e){return 'default'}
}
// normalizeIndustry (PR-2 Company Read GTM mode). Deterministic freeform-to-
// rubric-key mapper: p7 already classifies industry per company in its parsed
// JSON appendix, and this helper maps the freeform string ("healthcare
// technology", "hospital systems", "digital health" all -> 'healthcare') to
// one of the INDUSTRY_RUBRICS keys. No LLM call, no web search. Returns
// 'default' on any unmapped input.
function normalizeIndustry(freeform){
  if(typeof freeform!=='string')return 'default'
  const s=freeform.toLowerCase().trim()
  if(!s)return 'default'
  if(/\bhealth(care)?|hospital|medical|clinical|payor|payer|provider|nursing/.test(s))return 'healthcare'
  if(/\bsoftware|saas|tech\b|technology|internet|developer|engineering|infrastructure|cloud|devtools?|open source/.test(s))return 'tech'
  if(/\bbank|asset|insurance|broker|lending|fintech|finance|financial services|capital markets/.test(s))return 'financial_services'
  if(/\bpharma|biotech|biotechnology|drug|medical devices?|life sciences/.test(s))return 'pharma'
  if(/\bgovernment contractor|defense|federal services|government IT|gov-?con/.test(s))return 'government_contractor'
  if(/\bnonprofit|non-profit|ngo|foundation|charit/.test(s))return 'nonprofit'
  if(/\bhigher education|universit|college|education-policy/.test(s))return 'higher_education'
  if(/\bretail|consumer brand|consumer goods|e-commerce|ecommerce|hospitality|food service|restaurant|cpg/.test(s))return 'retail_consumer'
  if(/\bmanufactur|industrial|materials|energy|automotive|aerospace|chemical/.test(s))return 'manufacturing'
  return 'default'
}
// parseCompanies (hoisted from inline Download-CSV onClick — PR-2 Company Read).
// Consumed by both the Download-CSV button and the new per-company GTM cards.
// Reads the JSON appendix from p7's output first (preferred shape); falls back to
// the markdown company-block parser if the appendix is missing or invalid.
function parseCompanies(text){
  if(typeof text!=='string')return []
  const jsonMatch=text.match(/```json\s*([\s\S]*?)```/i)
  if(jsonMatch){try{const arr=JSON.parse(jsonMatch[1]);if(Array.isArray(arr)&&arr.length>0){const o2=arr.map(c=>({name:c.name||c.company||'',what:c.what||c.whatTheyDo||'',industry:c.industry||'',size:c.size||'',hq:c.hq||c.headquarters||'',fit:c.fit||c.whyItFits||'',growth:c.growth||c.growthSignal||'',contact:c.contact||c.contactName||'',contactLinkedIn:c.contactLinkedIn||c.linkedin||c.linkedIn||c.linkedInUrl||'',source:c.source||c.contactSource||'',emailConvention:c.emailConvention||c.email||'',website:c.website||c.url||''})).filter(c=>c.name);if(o2.length>0)return o2}}catch(e){}}
  const companies=[];let current=null
  const finalize=()=>{if(current&&(current.fit||current.growth||current.contact||current.emailConvention||current.what||current.industry||current.size||current.hq||current.source))companies.push(current);current=null}
  for(const line of text.split('\n')){
    const trimmed=line.trim()
    const nameMatch=trimmed.match(/^\*\*([^*]+?)\*\*\.?$/)
    if(nameMatch){const name=nameMatch[1].trim().replace(/\.$/,'');if(/^PART\s|^Company Name$|^Why it fits|^Growth signal|^Contact|^Email|^Source|^The Hook|^The Story|^The Close|^Paragraph\s|^What|^Industry|^Size|^HQ/i.test(name)){finalize();continue}finalize();current={name,what:'',industry:'',size:'',hq:'',fit:'',growth:'',contact:'',contactLinkedIn:'',source:'',emailConvention:'',website:''};continue}
    if(!current)continue
    if(/^What they do:/i.test(trimmed))current.what=trimmed.replace(/^What they do:\s*/i,'').trim()
    else if(/^Industry:/i.test(trimmed))current.industry=trimmed.replace(/^Industry:\s*/i,'').trim()
    else if(/^Size:/i.test(trimmed))current.size=trimmed.replace(/^Size:\s*/i,'').trim()
    else if(/^HQ:/i.test(trimmed))current.hq=trimmed.replace(/^HQ:\s*/i,'').trim()
    else if(/^Why it fits:/i.test(trimmed))current.fit=trimmed.replace(/^Why it fits:\s*/i,'').trim()
    else if(/^Growth signal:/i.test(trimmed))current.growth=trimmed.replace(/^Growth signal:\s*/i,'').trim()
    else if(/^Contact:/i.test(trimmed)){const c=trimmed.replace(/^Contact:\s*/i,'').trim();const li=c.match(/(https?:\/\/[^\s)]*linkedin\.com\/[^\s)]+)/i);if(li){current.contactLinkedIn=li[1];current.contact=c.replace(li[1],'').replace(/[|()\s]+$/,'').trim()}else current.contact=c}
    else if(/^Source:/i.test(trimmed))current.source=trimmed.replace(/^Source:\s*/i,'').trim()
    else if(/^Email:/i.test(trimmed)){const e=trimmed.replace(/^Email:\s*/i,'').trim();const parts=e.split('|').map(s=>s.trim());current.emailConvention=parts[0]||'';const url=parts.slice(1).join(' ').match(/(https?:\/\/\S+)/);if(url)current.website=url[1]}
  }
  finalize();return companies
}
// detectMissingCitations (PR-1 Company Read). Conservative structural detector:
// flags sentences containing specific factual claims (years, dollar amounts,
// percentages, named role transitions) that lack an adjacent source URL OR an
// explicit hedge. Tuned to minimize false positives — generic phrasings like
// "30 days" or "5 stars" do not trigger; only year mentions (19xx/20xx),
// dollar signs, percentage symbols, and named transition verbs do.
function detectMissingCitations(text){
  if(!text||typeof text!=='string')return []
  const violations=[]
  const sentences=text.split(/(?<=[.!?])\s+/)
  for(let i=0;i<sentences.length;i++){
    const sent=sentences[i]
    const hasYear=/\b(?:19|20)\d{2}\b/.test(sent)
    const hasDollar=/\$\s?\d/.test(sent)
    const hasPercent=/\b\d+(?:\.\d+)?\s?%/.test(sent)
    const hasNamedTransition=/\b(?:hired|promoted|appointed|joined|departed|stepped down|resigned)\s+(?:as|to|from)\b/i.test(sent)
    if(!(hasYear||hasDollar||hasPercent||hasNamedTransition))continue
    const window=sent+(sentences[i+1]||'').slice(0,80)
    const hasUrl=/https?:\/\/\S+/.test(window)
    const isHedged=/\b(?:public signal does not confirm|we could not verify|no source surfaces this|not independently verified)\b/i.test(window)
    if(!hasUrl&&!isHedged){
      violations.push({name:'missing-citation',match:sent.slice(0,160),note:'Numeric or named factual claim without an adjacent source URL or explicit hedge.'})
      if(violations.length>=8)break
    }
  }
  return violations
}
// detectFabricationTemplates (PR-1 Company Read). Conservative structural
// detector for invented-fact patterns the model uses when it does not have a
// real source. Each template is paired with an URL-proximity check; the
// template fires only when no URL appears within 120 chars after the match.
function detectFabricationTemplates(text){
  if(!text||typeof text!=='string')return []
  const violations=[]
  const templates=[
    {name:'fabrication-the-recent',re:/\bthe recent\s+[A-Z][a-z]+\b/g,note:'"The recent X" without a source URL within the same sentence is a common fabrication template. Either name the source or hedge.'},
    {name:'fabrication-reports-indicate',re:/\b(?:reports?|sources?|analysts?)\s+(?:indicate|suggest|note|say|report)\b/gi,note:'"Reports indicate" without naming the report is a fabrication template. Name the source.'},
    {name:'fabrication-it-has-been-reported',re:/\bit\s+has\s+been\s+reported\b/gi,note:'"It has been reported" with no named source is a fabrication template.'},
    {name:'fabrication-according-to-sources',re:/\baccording\s+to\s+(?:sources|industry observers|insiders)\b/gi,note:'"According to sources" with no named source is a fabrication template.'},
  ]
  for(const t of templates){
    const re=new RegExp(t.re.source,t.re.flags)
    let m
    while((m=re.exec(text))!==null){
      const after=text.slice(m.index,m.index+m[0].length+120)
      if(/https?:\/\/\S+/.test(after))continue
      violations.push({name:t.name,match:m[0].slice(0,80),note:t.note})
      if(violations.length>=8)return violations
    }
  }
  return violations
}
// buildCompanyReadCorrective: format detector violations into a corrective
// prompt suffix the model receives on retry. Quotes the violating fragments
// back so the model knows what to refuse on the next pass.
function buildCompanyReadCorrective(violations){
  if(!violations||violations.length===0)return ''
  const lines=violations.slice(0,3).map(v=>'- '+v.name+': "'+(v.match||'').replace(/"/g,'\\"').slice(0,140)+'" — '+v.note)
  return '\n\nCRITICAL: the previous generation contained '+violations.length+' citation or fabrication violation(s):\n'+lines.join('\n')+'\n\nEvery numeric claim, percentage, dollar amount, year reference, or named transition MUST have an adjacent source URL (https://...) in the same sentence, or the claim must be hedged as "public signal does not confirm this directly." Do not produce sentences of those shapes anywhere in your output.'
}
function renderResumeText(r){
  if(!r)return ''

  // Flatten structured bullets (matches buildResumeDoc's runsFromBullet and highlightParagraph)
  const bulletToText = (b) => {
    if (typeof b === 'string') return b
    if (Array.isArray(b)) return b.map(run => (run && run.text) || '').join('')
    if (b && typeof b === 'object') {
      const runs = Array.isArray(b.runs) ? b.runs : []
      const base = runs.map(run => (run && run.text) || '').join('')
      return b.roleTag ? `${base} (${b.roleTag})` : base
    }
    return ''
  }

  const h=r.header||{}
  const contact=[h.city||h.location,h.email,h.phone,h.linkedin].filter(Boolean).join(' · ')
  const lines=[]
  lines.push((h.name||'').toUpperCase())
  if(contact)lines.push(contact)
  lines.push('')
  lines.push('SUMMARY')
  lines.push(r.summary||'')
  const ka=(r.keyAccomplishments||[]).filter(Boolean)
  if(ka.length){
    lines.push('')
    lines.push('KEY ACCOMPLISHMENTS')
    ka.forEach(b=>lines.push('• '+bulletToText(b)))
  }
  lines.push('')
  lines.push('EXPERIENCE')
  lines.push('')
  ;(r.experience||[]).forEach((role,idx)=>{
    // Baseline shape supports titles:[{title,dates}] (multiple, for promotions);
    // Resume Refresh shape uses flat title/dates. Render either.
    const titleList=Array.isArray(role.titles)&&role.titles.length?role.titles:[{title:role.title,dates:role.dates}]
    titleList.forEach((t,ti)=>{
      const head=`${t.title||''}, ${role.company||''}`.replace(/^, /,'').replace(/, $/,'')
      lines.push(head)
      const sub=[t.dates,role.location].filter(Boolean).join(' · ')
      if(sub)lines.push(sub)
      if(ti===0&&role.context)lines.push(role.context)
    })
    ;(role.bullets||[]).forEach(b=>lines.push('• '+bulletToText(b)))
    if(idx<(r.experience||[]).length-1)lines.push('')
  })
  const edu=(r.education||[]).filter(Boolean)
  if(edu.length){
    lines.push('')
    lines.push('EDUCATION')
    lines.push('')
    edu.forEach(e=>{
      const deg=[e.degree,e.field].filter(Boolean).join(', ')
      const parts=[deg,e.institution,e.year].filter(Boolean).join(', ')
      lines.push(parts)
    })
  }
  const skillGroups=(r.skills||[]).filter(g=>g&&Array.isArray(g.items)&&g.items.length)
  if(skillGroups.length){
    lines.push('')
    lines.push('SKILLS')
    skillGroups.forEach(g=>{
      const items=g.items.map(s=>typeof s==='string'?s:(s&&s.skill)||'').filter(Boolean).join(', ')
      if(items)lines.push(g.category?`${g.category}: ${items}`:items)
    })
  }
  return lines.join('\n')
}

function resumeFilename(r){
  const name=(r&&r.header&&r.header.name)||'resume'
  const slug=name.toLowerCase().replace(/[^a-z0-9 ]/g,'').trim().split(/\s+/).join('_')
  const d=new Date().toISOString().slice(0,10)
  return `${slug||'resume'}_resume_${d}.docx`
}

// Lazy-load the docx writer on first use so it is split into its own chunk
// (Vite emits a separate chunk for the string-literal dynamic import) instead
// of riding in the main bundle. Memoized so buildResumeDoc and
// downloadResumeWord share a single module load per session.
let _docxModule = null
async function getDocx(){
  if(_docxModule) return _docxModule
  _docxModule = await import('docx')
  return _docxModule
}

async function buildResumeDoc(r){
  const { Document, Paragraph, TextRun, AlignmentType, BorderStyle, TabStopType } = await getDocx()
  const h = r.header || {}
  const contact = [h.city, h.email, h.phone, h.linkedin].filter(Boolean).join(' | ')
  const FONT = 'Garamond'
  const MARGIN = 1152 // 0.8 inch in twips
  const PAGE_W = 12240 // 8.5 inch in twips
  const CONTENT_W = PAGE_W - 2 * MARGIN // right-tab-stop position

  // Section header: small caps via uppercased text, character spacing, thin bottom rule
  const sectionHeader = (label) => new Paragraph({
    spacing: { before: 240, after: 120 },
    border: { bottom: { color: '000000', space: 4, style: BorderStyle.SINGLE, size: 6 } },
    children: [new TextRun({
      text: label,
      bold: true,
      size: 24,
      font: FONT,
      characterSpacing: 40
    })]
  })

  const bodyPara = (text) => new Paragraph({
    spacing: { after: 120, line: 280 },
    children: [new TextRun({ text, size: 22, font: FONT })]
  })

  // Map a bullet (string OR runs array) to an array of TextRuns
  const runsFromBullet = (bullet) => {
    if (typeof bullet === 'string') {
      return [new TextRun({ text: bullet, size: 22, font: FONT })]
    }
    if (Array.isArray(bullet)) {
      return bullet.map(run => new TextRun({
        text: (run && run.text) || '',
        bold: !!(run && run.bold),
        size: 22,
        font: FONT
      }))
    }
    return [new TextRun({ text: '', size: 22, font: FONT })]
  }

  // Highlight: object {runs, roleTag} OR plain string (backward-compat)
  const highlightParagraph = (item) => {
    let runs = []
    if (typeof item === 'string') {
      runs = [new TextRun({ text: item, size: 22, font: FONT })]
    } else if (item && typeof item === 'object') {
      const itemRuns = Array.isArray(item.runs) ? item.runs : []
      runs = itemRuns.map(rn => new TextRun({
        text: (rn && rn.text) || '',
        bold: !!(rn && rn.bold),
        size: 22,
        font: FONT
      }))
      if (item.roleTag) {
        runs.push(new TextRun({
          text: ` (${item.roleTag})`,
          italics: true,
          size: 22,
          font: FONT
        }))
      }
    }
    return new Paragraph({
      bullet: { level: 0 },
      spacing: { after: 120, line: 280 },
      children: runs
    })
  }

  const experienceBulletParagraph = (bullet) => new Paragraph({
    bullet: { level: 0 },
    spacing: { after: 100, line: 280 },
    children: runsFromBullet(bullet)
  })

  const children = []

  // Name: centered, uppercased, letter-spaced, larger size
  children.push(new Paragraph({
    alignment: AlignmentType.CENTER,
    spacing: { after: 80 },
    children: [new TextRun({
      text: (h.name || '').toUpperCase(),
      bold: true,
      size: 36, // 18pt
      font: FONT,
      characterSpacing: 120
    })]
  }))

  // Contact line: centered, pipe-separated
  if (contact) {
    children.push(new Paragraph({
      alignment: AlignmentType.CENTER,
      spacing: { after: 200 },
      children: [new TextRun({ text: contact, size: 20, font: FONT })]
    }))
  }

  // PROFESSIONAL SUMMARY
  children.push(sectionHeader('PROFESSIONAL SUMMARY'))
  children.push(bodyPara(r.summary || ''))

  // CAREER HIGHLIGHTS
  children.push(sectionHeader('CAREER HIGHLIGHTS'))
  ;(r.keyAccomplishments || []).forEach(item => children.push(highlightParagraph(item)))

  // PROFESSIONAL EXPERIENCE
  children.push(sectionHeader('PROFESSIONAL EXPERIENCE'))
  ;(r.experience || []).forEach(role => {
    const companyLeft = [role.company, role.location].filter(Boolean).join(', ')
    // Baseline shape carries titles:[{title,dates}] (multiple, for promotions) plus
    // an optional company context line; Resume Refresh shape uses flat title/dates.
    const titleList = Array.isArray(role.titles) && role.titles.length ? role.titles : [{ title: role.title, dates: role.dates }]
    const singleFlat = titleList.length === 1
    // Company on left; dates right-aligned via tab stop only when a single flat title.
    children.push(new Paragraph({
      spacing: { before: 160, after: 0 },
      tabStops: [{ type: TabStopType.RIGHT, position: CONTENT_W }],
      children: [
        new TextRun({ text: companyLeft, bold: true, size: 22, font: FONT }),
        new TextRun({ text: '\t', size: 22, font: FONT }),
        new TextRun({ text: singleFlat ? (titleList[0].dates || '') : '', size: 22, font: FONT })
      ]
    }))
    // Company context line (baseline only): what the company does + size marker.
    if (role.context) {
      children.push(new Paragraph({
        spacing: { after: 40 },
        children: [new TextRun({ text: role.context, italics: true, size: 20, font: FONT })]
      }))
    }
    titleList.forEach(t => {
      if (!t || !t.title) return
      if (singleFlat) {
        // Legacy look: title italic on its own line (dates already on company line).
        children.push(new Paragraph({
          spacing: { after: 80 },
          children: [new TextRun({ text: t.title, italics: true, size: 22, font: FONT })]
        }))
      } else {
        // Multiple titles: title left (italic), its own dates right-aligned.
        children.push(new Paragraph({
          spacing: { after: 60 },
          tabStops: [{ type: TabStopType.RIGHT, position: CONTENT_W }],
          children: [
            new TextRun({ text: t.title, italics: true, size: 22, font: FONT }),
            new TextRun({ text: '\t', size: 22, font: FONT }),
            new TextRun({ text: t.dates || '', size: 22, font: FONT })
          ]
        }))
      }
    })
    ;(role.bullets || []).forEach(b => children.push(experienceBulletParagraph(b)))
  })

  // EDUCATION
  children.push(sectionHeader('EDUCATION'))
  ;(r.education || []).forEach(e => {
    const left = e.institution || ''
    children.push(new Paragraph({
      spacing: { before: 80, after: 0 },
      tabStops: [{ type: TabStopType.RIGHT, position: CONTENT_W }],
      children: [
        new TextRun({ text: left, bold: true, size: 22, font: FONT }),
        new TextRun({ text: '\t', size: 22, font: FONT }),
        new TextRun({ text: e.year || '', size: 22, font: FONT })
      ]
    }))
    const deg = [e.degree, e.field].filter(Boolean).join(', ')
    if (deg) {
      children.push(new Paragraph({
        spacing: { after: 60 },
        children: [new TextRun({ text: deg, italics: true, size: 22, font: FONT })]
      }))
    }
  })

  // SKILLS (baseline schema extension). One paragraph per category: "Category: a, b, c".
  const skillGroups = (r.skills || []).filter(g => g && Array.isArray(g.items) && g.items.length)
  if (skillGroups.length) {
    children.push(sectionHeader('SKILLS'))
    skillGroups.forEach(g => {
      const items = g.items.map(s => typeof s === 'string' ? s : (s && s.skill) || '').filter(Boolean).join(', ')
      if (!items) return
      children.push(new Paragraph({
        spacing: { after: 80, line: 280 },
        children: g.category
          ? [new TextRun({ text: `${g.category}: `, bold: true, size: 22, font: FONT }), new TextRun({ text: items, size: 22, font: FONT })]
          : [new TextRun({ text: items, size: 22, font: FONT })]
      }))
    })
  }

  return new Document({
    creator: 'Reimagine',
    title: `${h.name || 'Resume'} Resume`,
    sections: [{
      properties: { page: { margin: { top: MARGIN, right: MARGIN, bottom: MARGIN, left: MARGIN } } },
      children
    }]
  })
}

async function downloadResumeWord(r){
  const { Packer }=await getDocx()
  const doc=await buildResumeDoc(r)
  const blob=await Packer.toBlob(doc)
  const url=URL.createObjectURL(blob)
  const a=document.createElement('a')
  a.href=url
  a.download=resumeFilename(r)
  document.body.appendChild(a)
  a.click()
  document.body.removeChild(a)
  URL.revokeObjectURL(url)
}

// Strip U+0000 — Postgres jsonb rejects NUL bytes; mammoth/pdf.js sometimes
// emit them from malformed sources and contaminate profile state.
const stripNulText=s=>typeof s==='string'?s.replace(/\x00/g,''):s

async function extractText(file){
  const ext=file.name.toLowerCase().split('.').pop()
  if(ext==='docx'||ext==='doc'){const mammoth=await import('mammoth');const ab=await file.arrayBuffer();const r=await mammoth.extractRawText({arrayBuffer:ab});return stripNulText(r.value)}
  if(ext==='pdf'){try{const lib=await loadPDFJS();const ab=await file.arrayBuffer();const pdf=await lib.getDocument({data:ab}).promise;let t='';for(let i=1;i<=pdf.numPages;i++){const pg=await pdf.getPage(i);const c=await pg.getTextContent();t+=c.items.map(x=>x.str).join(' ')+'\n'}if(t.trim().length<100)return "[This PDF appears to be image-based or browser-printed and couldn't be read as text. Try opening it and using Save As to save as a standard PDF, or simply paste the text below.]";return stripNulText(t)}catch{return "[This PDF couldn't be read automatically. If it was saved from a browser (like Edge or Chrome), try opening it and printing to a standard PDF, or just paste the text directly below.]"}}
  return new Promise((res,rej)=>{const r=new FileReader();r.onload=e=>res(stripNulText(e.target.result));r.onerror=rej;r.readAsText(file)})
}

// voice-allow
// AUDIENCE ANCHORING (Christine Holt feedback 2026-06-04). Silent reasoning that
// curates the candidate's signal for the target role's hiring audience. Brief A
// ships it on P.p6 (Bridge Story, free prose) only — the A/B showed it is
// cosmetic on the JSON-structured surfaces (p_res/p7/p8/p11), where Brief B will
// instead weight the schema's own selection logic. A function of `sel` because it
// interpolates the target role. Lives inside voice-allow: its OUTPUT-GUARD quotes
// "most candidates"/"most HR leaders" as negative examples, which would otherwise
// trip check-voice's comparative-standing patterns.
const AUDIENCE_ANCHORING=(sel)=>`AUDIENCE ANCHORING — silent reasoning, applied before writing the output.

Before producing the output below, do this work silently:

Name the specific audience for this role: who reads this output and decides whether to advance the candidate. Include their function (recruiter, hiring manager, executive, board), their experience level relative to the candidate, and their typical decision criteria for this kind of role.

List the few things (3-5) this audience cares about most when evaluating a candidate for ${sel}. Be specific to this role and this industry. Examples of specificity: "evidence of revenue impact at scale," "operating maturity in regulated environments," "comfort with executive presentation," "frameworks for org design at this stage," "domain credentials in the candidate's named industries." Refuse generic priorities ("strong communication skills," "team player") that could apply to any role.

Now filter the candidate's signal (resume, profile, reputation, prior outputs) through that audience-priority list. Surface only what scores high on the list. Translate or reframe items that have evidence but would not naturally read as relevant; omit items that have no audience-priority match. Inventory of credentials is the failure mode to refuse; curation for the audience is the success mode.

Do not include the audience-priority list in your output. It is silent reasoning.

OUTPUT-GUARD (load-bearing): never compare the candidate to "most candidates," "most HR leaders," "most professionals," or any unnamed group. Never write "this role wants X" or "this audience expects Y" in the user-facing output — that is lecturing the user about the role rather than producing the output. The audience-priority list informs WHAT you surface; it never becomes part of WHAT you write.`
// AUDIENCE_PRIORITY_CLAUSE (Brief B v2, 2026-06-14). Schema-internal weighting:
// interpolates INTO an existing selection sentence (vs AUDIENCE_ANCHORING's
// standalone preamble) because the A/B showed a preamble is cosmetic on
// JSON-structured surfaces — the schema's own selection instruction is the lever
// the model obeys. Scoped to P.p_res only; p8/p11/p7 did not move under this
// approach. In voice-allow for the same reason as AUDIENCE_ANCHORING (quotes
// "most candidates" as a negative example).
const AUDIENCE_PRIORITY_CLAUSE = (sel) => `weighted by what the audience hiring for ${sel} actually cares about when evaluating candidates: their function (recruiter, hiring manager, executive, board), the 3-5 specific decision criteria they apply for this kind of role and this industry, and which candidate signals they would foreground for those criteria. Refuse generic priorities ("strong communication skills," "team player") that could apply to any role. The audience-priority list is silent reasoning; do not emit it. The same OUTPUT-GUARD as AUDIENCE_ANCHORING applies: never compare the candidate to "most candidates" or any unnamed group, and never lecture about what "this role wants" in the output text.`;
