function Btn({onClick,disabled,secondary,small,children,style={}}){const base=small?S.sm:secondary?S.sec:S.btn;return <button style={{...base,opacity:disabled?0.5:1,...style}} onClick={onClick} disabled={disabled}>{children}</button>}
// GtmLearnMoreButton: full-width solid amber action on the GTM per-company
// card. Per the rename-and-prominence PR, replaces the inline outline Build
// affordance. Hover darkens one stop (#BA7517 → #854F0B). Module-scope so
// React reconciliation keeps the component identity stable across renders
// of the parent _renderGtmCompanyCard helper (defining components inside a
// render path would mint a new component type per render and unmount on every
// update). Hover state lives in the button via useState.
function GtmLearnMoreButton({companyName,busy,waiting,onClick}){
  const[hover,setHover]=useState(false)
  const disabled=busy||waiting
  const bg=(!disabled&&hover)?'#854F0B':'#BA7517'
  const label=busy?'Building…':waiting?'Wait for the Go-to-Market build to finish.':(companyName&&companyName.trim()?'Learn more about '+companyName.trim():'Learn more about this company')
  return <button
    onClick={onClick}
    disabled={disabled}
    onMouseEnter={()=>setHover(true)}
    onMouseLeave={()=>setHover(false)}
    onFocus={()=>setHover(true)}
    onBlur={()=>setHover(false)}
    style={{
      display:'flex',
      alignItems:'center',
      justifyContent:'center',
      gap:10,
      width:'100%',
      padding:'14px 20px',
      background:bg,
      border:'none',
      color:'#FFFFFF',
      fontSize:15,
      fontWeight:500,
      fontFamily:'inherit',
      cursor:disabled?'default':'pointer',
      opacity:disabled?0.7:1,
      transition:'background-color 0.15s ease',
    }}
  >
    {!disabled&&<Sparkles size={18}/>}
    <span>{label}</span>
    {!disabled&&<ArrowRight size={18}/>}
  </button>
}
