const correctionsBlock = (corrections) => {
  if (!corrections || corrections.length === 0) return ''
  const recent = corrections.slice(-20)
  const lines = recent.map(c => `- ${c.text}`).join('\n')
  // Fed as ground-truth facts in the person's own terms, NOT meta-labeled as
  // "corrections the user made" — that framing leaks into the prose (the model
  // narrates the process). Presented this way the model absorbs them as input.
  return `The person has told us the following directly about themselves and their work. Treat each as established, ground-truth fact and let it shape this read as naturally as any other evidence; where it differs from the resume or other source material, it takes precedence.

${lines}

`
}

// Foundation C-arch Phase D.1 + D.2a (2026-05-27, PR #90 + this PR).
// Generalized synthesis-context helper for downstream prompt consumption.
// Emits a labeled "PERSONAL BRAND SYNTHESIS (structured)" block that
// signals to the model the values are canonical input from the Personal
// Brand step, not a re-derivation target. Carries through-line, per-axis
// dimensional fit, and the strongest topAnchors as discrete signals the
// model can reference without re-deriving from the p3 prose.
//
// D.1 piloted on p5 (Focus deep dive) and p8 (LinkedIn Remix). D.2a
// extended to p4 (replacing the earlier formatStructuredFitRead helper),
// p6 (Bridge Story), p7 (Go-to-Market), p_res (Resume Refresh), p11
// (Interview Prep), op (Opportunity Playbook), and income (Income Now).
// p9 (Industry Background) is intentionally not wired: it is a reference
// guide for sector vocabulary, not a synthesis surface, and its prompt
// does not consume outs.p3 today. Wiring it in would be a scope
// expansion (adding a new dependency), not a parallel migration.
//
// Augment-not-replace pattern: each downstream prompt keeps its existing
// asText(outs.p3) prose injection. The structured block is added
// immediately after so the model sees both the analytical prose AND the
// canonical structured signals.
//
// Graceful fallback per the consult: returns empty string when
// outs.p3_structured is missing, malformed, or has no through-line
// (load-bearing field). Each block (dim fit, anchors) appears only when
// populated; partial structured input is acceptable.
