      const opts={...(key==='p11'?{maxTokens:8000}:{maxTokens:5000}),profileBlock:buildUserProfileBlock(pc,opOuts),step:key}
      const r=await callClaudeWithVoiceGate(fn,opts,{step:key,onEvent:logVoiceEvent})
